The `StatefulGamepad` class provides edge-detection for button state. It uses dual-array flip-flopping (current vs previous frame) to detect transitions:

```typescript
getButtonDown(id: string): boolean {
  const idx = this.buttonMapping.get(id);
  return idx !== undefined
    ? (this.pressedArrs[this.currentIndex][idx] &
        ~this.pressedArrs[this.previousIndex][idx]) !== 0
    : false;
}

getButtonUp(id: string): boolean {
  const idx = this.buttonMapping.get(id);
  return idx !== undefined
    ? (~this.pressedArrs[this.currentIndex][idx] &
        this.pressedArrs[this.previousIndex][idx]) !== 0
    : false;
}

getButtonPressed(id: string): boolean {
  return !!this.getButtonState(id, this.pressedArrs);
}
```

